INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", 10, "", 11, "", "", 105831, "", "うわぁ～…！\n大きくなりすぎて\nやばいですね☆", 1010020);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", "", "", 91, "", "", 0, "", "", 1010021);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", 10, "", 11, "", "", 105931, "", "うえきちゃんが\nどこまで続くのか\n分からないほどです", 1010022);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", "", "", 91, "", "", 0, "", "", 1010023);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", 10, "", 11, "", "", 112631, "", "こういうのってさ\n上がどうなってるか\n見てみたいよね！", 1010024);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", "", "", 91, "", "", 0, "", "", 1010025);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", 10, "", 11, "", "", 112531, "", "確かにね…それに\nこうなった理由も\n分かるかも", 1010026);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", "", "", 91, "", "", 0, "", "", 1010027);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", 10, "", 11, "", "", 106031, "", "ま、興味はあるし\n付き合ってあげるわ", 1010028);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", "", "", 91, "", "", 0, "", "", 1010029);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", 10, "", 11, "", "", 112431, "", "はい♪みなさんで\n頂上を目指して\n頑張りましょう！", 1010030);
INSERT INTO `v1_deba2d090321f3228f801bbe8305ab8f9829d138251d5d216c49ad2c7d389cd4` VALUES (1, "", "", "", 91, "", "", 0, "", "", 1010031);
